{
  "schemaVersion": 2,
  "id": "warm-selection-pack",
  "name": "Warm Selection Pack",
  "version": "1.0.0",
  "entry": null,
  "pluginType": "ui-snippet",
  "capabilities": [
    "theme.snippet"
  ],
  "platforms": [
    "desktop",
    "web"
  ],
  "requiresRestart": false,
  "experimental": false,
  "minAppVersion": "0.6.0",
  "maxAppVersion": null,
  "permissions": {
    "theme": {
      "register": true
    }
  },
  "contributes": {
    "theme": {
      "style": [],
      "snippets": [
        {
          "file": "theme/snippets/warm-selection-pack.css",
          "id": "warm-selection-pack",
          "label": "Warm Selection",
          "description": "Stronger text selection tint than the built-in 18% default.",
          "defaultEnabled": false
        }
      ],
      "tokens": [],
      "defaultEnable": {}
    },
    "commands": [],
    "preferencesSections": [],
    "panels": []
  }
}

/**
 * Warm selection — UI snippet
 *
 * Stronger accent-tinted text selection than the built-in default (accent 18%).
 * Copy to ~/.luna/theme/snippets/warm-selection.css → Rescan → enable in UI snippets.
 */

.preview-pane.markdown-visual-editor .ProseMirror ::selection,
.markdown-preview-view ::selection {
  background: color-mix(in srgb, var(--accent) 32%, transparent);
}

.source-pane .cm-editor .cm-content ::selection {
  background: color-mix(in srgb, var(--accent) 28%, transparent);
}
